-- Multi-store system migration
-- Creates stores table, adds store_id to products and users

-- Step 1: stores table
CREATE TABLE IF NOT EXISTS stores (
  id varchar PRIMARY KEY DEFAULT gen_random_uuid(),
  owner_id varchar NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  name text NOT NULL,
  description text,
  address text,
  phone text,
  logo text,
  is_active boolean NOT NULL DEFAULT true,
  deleted_at timestamp,
  created_at timestamp NOT NULL DEFAULT now(),
  updated_at timestamp NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_stores_owner  ON stores(owner_id);
CREATE INDEX IF NOT EXISTS idx_stores_active ON stores(is_active);
CREATE INDEX IF NOT EXISTS idx_stores_name   ON stores(name);

-- Step 2: products.store_id FK
ALTER TABLE products
  ADD COLUMN IF NOT EXISTS store_id varchar REFERENCES stores(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_products_store ON products(store_id);

-- Step 3: users.store_id FK (bidirectional link for store-role users)
ALTER TABLE users
  ADD COLUMN IF NOT EXISTS store_id varchar REFERENCES stores(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_users_store ON users(store_id);

import { getApiUrl } from "@/lib/query-client";

type EventHandler = (data?: unknown) => void;

class WsManager {
  private ws: WebSocket | null = null;
  private handlers: Map<string, Set<EventHandler>> = new Map();
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
  private shouldConnect = false;
  private authToken: string | null = null;

  private getWsUrl(): string {
    const apiUrl = getApiUrl().replace(/\/$/, "");
    return apiUrl.replace(/^http/, "ws") + "/ws";
  }

  /** Call after login with the JWT so the server can bind this socket to the user. */
  authenticate(token: string): void {
    this.authToken = token;
    this._sendAuth();
  }

  /** Remove auth binding (e.g. on logout). */
  clearAuth(): void {
    this.authToken = null;
  }

  connect(): void {
    this.shouldConnect = true;
    if (
      this.ws?.readyState === WebSocket.OPEN ||
      this.ws?.readyState === WebSocket.CONNECTING
    ) {
      return;
    }
    this._open();
  }

  disconnect(): void {
    this.shouldConnect = false;
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }
    this.ws?.close();
    this.ws = null;
  }

  private _sendAuth(): void {
    if (this.authToken && this.ws?.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify({ type: "auth", token: this.authToken }));
    }
  }

  private _open(): void {
    try {
      this.ws = new WebSocket(this.getWsUrl());

      this.ws.onopen = () => {
        if (this.reconnectTimer) {
          clearTimeout(this.reconnectTimer);
          this.reconnectTimer = null;
        }
        console.log("[WS] Connected");
        // Immediately authenticate if we have a token
        this._sendAuth();
      };

      this.ws.onmessage = (event) => {
        try {
          const { event: evtName, data } = JSON.parse(event.data as string);
          const handlers = this.handlers.get(evtName);
          handlers?.forEach((h) => h(data));
        } catch {}
      };

      this.ws.onclose = () => {
        console.log("[WS] Disconnected");
        if (this.shouldConnect) {
          this.reconnectTimer = setTimeout(() => this._open(), 3000);
        }
      };

      this.ws.onerror = () => {
        this.ws?.close();
      };
    } catch {
      if (this.shouldConnect) {
        this.reconnectTimer = setTimeout(() => this._open(), 3000);
      }
    }
  }

  on(event: string, handler: EventHandler): () => void {
    if (!this.handlers.has(event)) {
      this.handlers.set(event, new Set());
    }
    this.handlers.get(event)!.add(handler);
    return () => {
      this.handlers.get(event)?.delete(handler);
    };
  }
}

export const wsManager = new WsManager();

