    38→async function fetchRoute(from: Coord, to: Coord): Promise<Coord[]> {
    39→  try {
    40→    const url =
    41→      `https://router.project-osrm.org/route/v1/driving/` +
    42→      `${from.longitude},${from.latitude};${to.longitude},${to.latitude}` +
    43→      `?overview=full&geometries=geojson`;
    44→    const res = await fetch(url);
    45→    const data = await res.json();
    46→    if (data.code !== "Ok" || !data.routes?.length) return [from, to];
    47→    return (data.routes[0].geometry.coordinates as [number, number][]).map(
    48→      ([lng, lat]) => ({ latitude: lat, longitude: lng })
    49→    );
    50→  } catch {
    51→    return [from, to];
    52→  }
    53→}
